import{_ as a,c as r,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"z.ai 統合: 能力境界の詳細解説 | Antigravity-Manager","description":"Antigravity Tools の z.ai 統合境界を把握します。リクエストルーティング、dispatch_mode 分散、モデルマッピング、Header セキュリティポリシー、MCP リバースプロキシと制限を理解し、誤判断を回避します。","frontmatter":{"title":"z.ai 統合: 能力境界の詳細解説 | Antigravity-Manager","sidebarTitle":"z.ai 境界一覧","subtitle":"z.ai 統合: 能力境界の詳細解説","description":"Antigravity Tools の z.ai 統合境界を把握します。リクエストルーティング、dispatch_mode 分散、モデルマッピング、Header セキュリティポリシー、MCP リバースプロキシと制限を理解し、誤判断を回避します。","tags":["z.ai","MCP","Claude","能力境界"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"ja/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function d(c,e,l,s,n,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="z-ai-統合の能力境界-実装済み-vs-明確に未実装" tabindex="-1">z.ai 統合の能力境界（実装済み vs 明確に未実装） <a class="header-anchor" href="#z-ai-統合の能力境界-実装済み-vs-明確に未実装" aria-label="Permalink to &quot;z.ai 統合の能力境界（実装済み vs 明確に未実装）&quot;">​</a></h1><p>このドキュメントは Antigravity Tools の z.ai の「境界」のみを説明し、「接続方法」は説明しません。特定の機能が有効になっていないと気づいた場合、ここで照合してください：それはまだ有効になっていないのか、設定されていないのか、それとも最初から実装されていないのか。</p><h2 id="学べること" tabindex="-1">学べること <a class="header-anchor" href="#学べること" aria-label="Permalink to &quot;学べること&quot;">​</a></h2><ul><li>z.ai に期待できることかどうかを判断できる：「実装済み」と「明確に未実装」の区別</li><li>z.ai がどのエンドポイントにのみ影響するか（およびどのエンドポイントには完全に影響しないか）を明確にする</li><li>各結論のソースコード/ドキュメントの証拠（GitHub 行番号リンク付き）を確認し、自分で再検証できるようにする</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>あなたはすでに Antigravity Tools で z.ai を有効にしているかもしれませんが、使用すると以下のような疑問に直面しているかもしれません：</p><ul><li>なぜ一部のリクエストは z.ai を経由し、一部は全く経由しないのか？</li><li>MCP エンドポイントは「完全な MCP Server」として使用できるか？</li><li>UI で見えるスイッチは、実際の実装に対応しているのか？</li></ul><h2 id="z-ai-統合とは-このプロジェクトで" tabindex="-1">z.ai 統合とは（このプロジェクトで）？ <a class="header-anchor" href="#z-ai-統合とは-このプロジェクトで" aria-label="Permalink to &quot;z.ai 統合とは（このプロジェクトで）？&quot;">​</a></h2><p><strong>z.ai 統合</strong>は Antigravity Tools ではオプションの「アップストリームプロバイダー + MCP 拡張」です。特定の条件下でのみ Claude プロトコルリクエストを引き継ぎ、MCP Search/Reader リバースプロキシと最小限の Vision MCP 内蔵サーバーを提供します。全プロトコル、全機能の置換ソリューションではありません。</p><div class="info custom-block"><p class="custom-block-title">一言で記憶</p><p>z.ai は「Claude リクエストのオプションのアップストリーム + 一連のオン/オフ可能な MCP エンドポイント」として使用でき、「z.ai のすべての機能を完全に取り込む」ものと期待しないでください。</p></div><h2 id="実装済み-安定して利用可能-ソースコードを基準" tabindex="-1">実装済み：安定して利用可能（ソースコードを基準） <a class="header-anchor" href="#実装済み-安定して利用可能-ソースコードを基準" aria-label="Permalink to &quot;実装済み：安定して利用可能（ソースコードを基準）&quot;">​</a></h2><h3 id="_1-claude-プロトコルのみが-z-ai-を経由する-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Claude プロトコルのみが z.ai を経由する（/v1/messages + /v1/messages/count_tokens） <a class="header-anchor" href="#_1-claude-プロトコルのみが-z-ai-を経由する-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Claude プロトコルのみが z.ai を経由する（/v1/messages + /v1/messages/count_tokens）&quot;">​</a></h3><p>z.ai の Anthropic アップストリーム転送は、Claude ハンドラーの z.ai ブランチでのみ発生します：</p><ul><li><code>POST /v1/messages</code>：<code>use_zai=true</code> の場合、<code>forward_anthropic_json(...)</code> を呼び出して JSON リクエストを z.ai Anthropic 互換エンドポイントに転送します</li><li><code>POST /v1/messages/count_tokens</code>：z.ai が有効な場合も同様に転送します。それ以外の場合はプレースホルダー <code>{input_tokens:0, output_tokens:0}</code> を返します</li></ul><p>証拠：</p><ul><li>z.ai ブランチ選択と転送エントリ：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>count_tokens の z.ai ブランチとプレースホルダー返却：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai Anthropic 転送実装：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">「レスポンスストリーミング」の理解方法</p><p><code>forward_anthropic_json</code> はアップストリームレスポンスボディを <code>bytes_stream()</code> でストリーミングしてクライアントに返し、SSE を解析しません（<code>providers/zai_anthropic.rs</code> の Response body 構築を参照）。</p></div><h3 id="_2-スケジューリングモード-dispatch-mode-の「実際の意味」" tabindex="-1">2) スケジューリングモード（dispatch_mode）の「実際の意味」 <a class="header-anchor" href="#_2-スケジューリングモード-dispatch-mode-の「実際の意味」" aria-label="Permalink to &quot;2) スケジューリングモード（dispatch_mode）の「実際の意味」&quot;">​</a></h3><p><code>dispatch_mode</code> は <code>/v1/messages</code> が z.ai を経由するかどうかを決定します：</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>何が起こるか</th><th>証拠</th></tr></thead><tbody><tr><td><code>off</code></td><td>z.ai を使用しない</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>すべての Claude リクエストが z.ai を経由する</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Google プールが使用不可（0 アカウントまたは「使用可能なアカウントなし」）の場合のみ z.ai を経由する</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>z.ai を「追加の 1 つのスロット」としてラウンドロビンに参加させる（必ずヒットする保証はない）</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">pooled のよくある誤解</p><p><code>pooled</code> は「z.ai と Google アカウントプールの両方を使用し、重みに基づいて安定して分散する」わけではありません。コードには明確に「no strict guarantees」と書かれており、本質的にはラウンドロビンスロット（<code>slot == 0</code> の場合のみ z.ai を経由）です。</p></div><h3 id="_3-モデルマッピング-claude-モデル名が-z-ai-の-glm-にどう変換されるか" tabindex="-1">3) モデルマッピング：Claude モデル名が z.ai の glm-* にどう変換されるか <a class="header-anchor" href="#_3-モデルマッピング-claude-モデル名が-z-ai-の-glm-にどう変換されるか" aria-label="Permalink to &quot;3) モデルマッピング：Claude モデル名が z.ai の glm-* にどう変換されるか&quot;">​</a></h3><p>z.ai に転送する前に、リクエストボディに <code>model</code> フィールドがある場合、次のように書き換えられます：</p><ol><li><code>proxy.zai.model_mapping</code> の完全一致（元の文字列と小文字のキーを同時にサポート）</li><li><code>zai:&lt;model&gt;</code> プレフィックス：<code>zai:</code> を削除して直接使用</li><li><code>glm-*</code>：変更なし</li><li><code>claude-*</code> 以外：変更なし</li><li><code>claude-*</code> で <code>opus/haiku</code> を含む：<code>proxy.zai.models.opus/haiku</code> にマッピング；それ以外はデフォルトで <code>sonnet</code></li></ol><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-転送時の-header-セキュリティポリシー-ローカルプロキシキーの漏洩を回避" tabindex="-1">4) 転送時の Header セキュリティポリシー（ローカルプロキシキーの漏洩を回避） <a class="header-anchor" href="#_4-転送時の-header-セキュリティポリシー-ローカルプロキシキーの漏洩を回避" aria-label="Permalink to &quot;4) 転送時の Header セキュリティポリシー（ローカルプロキシキーの漏洩を回避）&quot;">​</a></h3><p>z.ai アップストリーム転送は「すべての Header をそのまま渡す」のではなく、2 層の防御を行います：</p><ul><li>一部の Header のみを許可（例：<code>content-type</code>、<code>accept</code>、<code>anthropic-version</code>、<code>user-agent</code>）</li><li>z.ai の API Key をアップストリームに注入（クライアントが使用する認証方式を優先：<code>x-api-key</code> または <code>Authorization: Bearer ...</code>）</li></ul><p>証拠：</p><ul><li>Header ホワイトリスト：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>z.ai auth の注入：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="実装済み-mcp-search-reader-リバースプロキシ-vision-内蔵" tabindex="-1">実装済み：MCP（Search/Reader リバースプロキシ + Vision 内蔵） <a class="header-anchor" href="#実装済み-mcp-search-reader-リバースプロキシ-vision-内蔵" aria-label="Permalink to &quot;実装済み：MCP（Search/Reader リバースプロキシ + Vision 内蔵）&quot;">​</a></h2><h3 id="_1-mcp-search-reader-z-ai-の-mcp-エンドポイントへのリバースプロキシ" tabindex="-1">1) MCP Search/Reader：z.ai の MCP エンドポイントへのリバースプロキシ <a class="header-anchor" href="#_1-mcp-search-reader-z-ai-の-mcp-エンドポイントへのリバースプロキシ" aria-label="Permalink to &quot;1) MCP Search/Reader：z.ai の MCP エンドポイントへのリバースプロキシ&quot;">​</a></h3><p>ローカルエンドポイントとアップストリームアドレスは固定されています：</p><table tabindex="0"><thead><tr><th>ローカルエンドポイント</th><th>アップストリームアドレス</th><th>スイッチ</th><th>証拠</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 は「ネットワークの問題」ではありません</p><p><code>proxy.zai.mcp.enabled=false</code>、または対応する <code>web_search_enabled/web_reader_enabled=false</code> の場合、これらのエンドポイントは直接 404 を返します。</p></div><p>証拠：</p><ul><li>MCP 総スイッチと z.ai キー検証：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>ルーティング登録：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-「最小限の-streamable-http-mcp」内蔵サーバー" tabindex="-1">2) Vision MCP：「最小限の Streamable HTTP MCP」内蔵サーバー <a class="header-anchor" href="#_2-vision-mcp-「最小限の-streamable-http-mcp」内蔵サーバー" aria-label="Permalink to &quot;2) Vision MCP：「最小限の Streamable HTTP MCP」内蔵サーバー&quot;">​</a></h3><p>Vision MCP はリバースプロキシではなく、ローカル内蔵実装です：</p><ul><li>エンドポイント：<code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> でサポート：<code>initialize</code>、<code>tools/list</code>、<code>tools/call</code></li><li><code>GET</code> で SSE keepalive を返却（初期化されたセッションが必要）</li><li><code>DELETE</code> でセッションを終了</li></ul><p>証拠：</p><ul><li>ハンドラーメインエントリとメソッドディスパッチ：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li><code>initialize</code>、<code>tools/list</code>、<code>tools/call</code> の実装：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Vision MCP の「最小実装」の位置付け：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-ツールセット-8-つ-とファイルサイズ制限" tabindex="-1">3) Vision MCP ツールセット（8 つ）とファイルサイズ制限 <a class="header-anchor" href="#_3-vision-mcp-ツールセット-8-つ-とファイルサイズ制限" aria-label="Permalink to &quot;3) Vision MCP ツールセット（8 つ）とファイルサイズ制限&quot;">​</a></h3><p>ツールリストは <code>tool_specs()</code> から取得されます：</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>ローカルファイルは読み取られて <code>data:&lt;mime&gt;;base64,...</code> にエンコードされ、同時にハード制限があります：</p><ul><li>画像の上限は 5 MB（<code>image_source_to_content(..., 5)</code>）</li><li>動画の上限は 8 MB（<code>video_source_to_content(..., 8)</code>）</li></ul><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="明確に未実装-期待しないでください-ドキュメント宣言と実装の詳細を基準" tabindex="-1">明確に未実装 / 期待しないでください（ドキュメント宣言と実装の詳細を基準） <a class="header-anchor" href="#明確に未実装-期待しないでください-ドキュメント宣言と実装の詳細を基準" aria-label="Permalink to &quot;明確に未実装 / 期待しないでください（ドキュメント宣言と実装の詳細を基準）&quot;">​</a></h2><h3 id="_1-z-ai-使用量-予算監視-usage-budget-は未実装" tabindex="-1">1) z.ai 使用量/予算監視（usage/budget）は未実装 <a class="header-anchor" href="#_1-z-ai-使用量-予算監視-usage-budget-は未実装" aria-label="Permalink to &quot;1) z.ai 使用量/予算監視（usage/budget）は未実装&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> に明確に「not implemented yet」と記載されています。これは以下を意味します：</p><ul><li>Antigravity Tools が z.ai の usage/budget クエリやアラートを提供することは期待できません</li><li>クォータガバナンス（Quota Protection）も自動的に z.ai の予算/使用量データを読み取りません</li></ul><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-は完全な-mcp-server-ではありません" tabindex="-1">2) Vision MCP は完全な MCP Server ではありません <a class="header-anchor" href="#_2-vision-mcp-は完全な-mcp-server-ではありません" aria-label="Permalink to &quot;2) Vision MCP は完全な MCP Server ではありません&quot;">​</a></h3><p>Vision MCP は現在、ツール呼び出しに「十分な」最小実装として位置づけられており、prompts/resources、resumability、streamed tool output などはまだ実装されていません。</p><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-は-z-ai-の実際のモデルリストを反映しません" tabindex="-1">3) <code>/v1/models/claude</code> は z.ai の実際のモデルリストを反映しません <a class="header-anchor" href="#_3-v1-models-claude-は-z-ai-の実際のモデルリストを反映しません" aria-label="Permalink to &quot;3) `/v1/models/claude` は z.ai の実際のモデルリストを反映しません&quot;">​</a></h3><p>このエンドポイントが返すモデルリストはローカルの内蔵マッピングとカスタムマッピング（<code>get_all_dynamic_models</code>）から取得され、z.ai アップストリームの <code>/v1/models</code> をリクエストしません。</p><p>証拠：</p><ul><li>ハンドラー：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>リスト生成ロジック：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="設定フィールド一覧-z-ai-関連" tabindex="-1">設定フィールド一覧（z.ai 関連） <a class="header-anchor" href="#設定フィールド一覧-z-ai-関連" aria-label="Permalink to &quot;設定フィールド一覧（z.ai 関連）&quot;">​</a></h2><p>z.ai 設定は <code>ProxyConfig.zai</code> の下にあり、以下のフィールドが含まれます：</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code>（<code>off/exclusive/pooled/fallback</code>）</li><li><code>model_mapping</code>（完全一致で上書き）</li><li><code>models.{opus,sonnet,haiku}</code>（Claude ファミリーのデフォルトマッピング）</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>デフォルト値（base_url / デフォルトモデル）も同じファイルにあります：</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>証拠：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="本レッスンのまとめ" tabindex="-1">本レッスンのまとめ <a class="header-anchor" href="#本レッスンのまとめ" aria-label="Permalink to &quot;本レッスンのまとめ&quot;">​</a></h2><ul><li>z.ai は現在 Claude プロトコル（<code>/v1/messages</code> + <code>count_tokens</code>）のみを引き継ぎ、他のプロトコルエンドポイントは「自動的に z.ai を経由する」わけではありません</li><li>MCP Search/Reader はリバースプロキシです。Vision MCP はローカルの最小実装であり、完全な MCP Server ではありません</li><li><code>/v1/models/claude</code> のモデルリストはローカルマッピングから取得され、z.ai アップストリームの実際のモデルを表すものではありません</li></ul><hr><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../changelog/release-notes/">バージョン進化</a></strong> を学習します。</p></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>z.ai 統合範囲（Claude プロトコル + MCP + Vision MCP）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>z.ai スケジューリングモードとモデルのデフォルト値</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai デフォルト base_url / デフォルトモデル</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code> が z.ai を経由するかどうかの選択ロジック</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td><code>/v1/messages/count_tokens</code> の z.ai 転送とプレースホルダー返却</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>z.ai Anthropic アップストリーム転送（JSON 転送 + レスポンスストリーミング返却）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>z.ai モデルマッピングルール（map_model_for_zai）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Header ホワイトリスト + z.ai auth の注入</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>MCP Search/Reader リバースプロキシとスイッチ</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision MCP 最小実装の位置付け（完全な MCP Server ではない）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Vision ツールリストと制限（tool_specs + ファイルサイズ + stream=false）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td><code>/v1/models/claude</code> モデルリストのソース（ローカルマッピング、アップストリームを照会しない）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>使用量/予算監視未実装（ドキュメント宣言）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const u=a(i,[["render",d]]);export{b as __pageData,u as default};
